// Script Continued Below

// RJ - RJ - STRY0062760 Fix Script Story Number Here
// Get all top tasks
var grTopTask = new GlideRecord('x_153465_discovert_route_task_instance');

// Find all Top Tasks
grTopTask.addNullQuery('parent');
grTopTask.orderBy('sys_created_on');
grTopTask.query();
while (grTopTask.next()){
	// I put this if statement in to keep from creating multiple tree objects for a top task
	// this will reset all of the values for shared documents throughout the tree, but at least will not create multiple tree objects
	if(grTopTask.u_task_tree.nil()){
		// if we have a Task Tree, don't create again

		// Set the Top Task Field on the top task
		grTopTask.u_top_task = grTopTask.sys_id;
		// by default turn on shared documents and shared attachments for all top tasks
		grTopTask.u_shared_documents = true;
		grTopTask.u_shared_attachments = true;

		// create the task tree object for the top task
		var grTaskTree = new GlideRecord('x_153465_discovert_task_tree');
		grTaskTree.initialize();
		// relate the task tree object to the top task
		// set the Shared Task Label for DocInt on all tree objects (NOTE: this is done in the script)
		grTaskTree.u_task_ref = grTopTask.sys_id;
		grTaskTree.insert();
		// now relate  the top task to the task tree
		grTopTask.u_task_tree = grTaskTree.sys_id;

		// update the top task with the new field values
		grTopTask.update();
		// call the recursive 
		updateChildren(grTopTask);

	}
}

// Get all children of Top Tasks and update the top task fields
// recurively get all children and update the top task down the tree
function updateChildren(grParent){
	var grChildren = new GlideRecord("x_153465_discovert_route_task_instance");
	grChildren.addQuery('parent', grParent.sys_id);
	grChildren.query();
	while(grChildren.next()){
		grChildren.u_top_task = grParent.u_top_task;
		grChildren.u_task_tree = grParent.u_task_tree;

		grChildren.update();
		// recursively set the top task down the tree
		updateChildren(grChildren);
	}
}
